import java.util.*;
import java.util.stream.*;

public class Main {
    static class Animal { String sound() { return "unknown"; } }
    static final class Dog extends Animal { @Override String sound() { return "woof"; } }
    static final class Cat extends Animal { @Override String sound() { return "meow"; } }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        Animal animal = input.next().equals("dog") ? new Dog() : new Cat();
        System.out.println(animal.sound());
    }
}
